                    <input style={{...F, fontSize: 12, padding: "7px 10px"}} placeholder="opmerking..." value={item.opmerking} onChange={e => { const a=[...gas.checklistItems]; a[i]={...a[i],opmerking:e.target.value}; setGas({...gas,checklistItems:a}); }} />
